import { GoogleGenAI, GenerateContentResponse } from "@google/genai";
import { AppLanguage } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

const getSystemInstruction = (lang: AppLanguage) => {
  const base = `You are 'Link', the cheerful AI guide for "Shanghai We Link!".

  FORMATTING RULES (CRITICAL):
  - Always use DOUBLE line breaks between paragraphs.
  - For lists, use '1.', '2.', '3.' and start each item on a NEW line.
  - Use 2-3 emojis per message to stay lively.
  - Keep sentences concise but warm.

  CONTENT:
  - Be a Shanghai expert. 
  - If asked about coffee, food, or metro, give specific, actionable tips.`;

  const languageMap: Record<AppLanguage, string> = {
    'EN': `${base}\nRespond in English.`,
    'CN': `${base}\n请用中文回复。段落之间必须使用两个换行符。列表项必须另起一行。语气要亲切、充满活力。`,
    'JP': `${base}\n日本語で答えてください。段落の間に空行を入れてください。`,
    'KR': `${base}\n한국어로 답변해 주세요. 단락 사이에 공백을 두세요.`,
    'FR': `${base}\nRépondez en français. Utilisez des doubles sauts de ligne.`,
    'ES': `${base}\nResponde en español. Usa dobles saltos de línea.`,
    'DE': `${base}\nAntworte auf Deutsch. Verwenden Sie doppelte Zeilenumbrüche.`,
    'IT': `${base}\nRispondi in italiano. Usa doppi salti di riga.`,
    'PT': `${base}\nResponda em português. Use quebras de linha duplas.`,
    'RU': `${base}\nОтвечайте на русском языке. Используйте двойные разрывы строк.`,
    'AR': `${base}\nيرجى الرد باللغة العربية. استخدم فواصل أسطر مزدوجة.`
  };

  return languageMap[lang] || languageMap['EN'];
};

export const sendMessageToLink = async (message: string, lang: AppLanguage = 'EN'): Promise<string> => {
  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: message,
      config: {
        systemInstruction: getSystemInstruction(lang),
        temperature: 0.8,
      },
    });
    return response.text || "Oops! Link is a bit shy right now. Try again? 🏮";
  } catch (error) {
    console.error("Gemini API Error:", error);
    return "Link had a small technical hiccup. Let's try again! 🏙️";
  }
};

/**
 * FEATURE 1: Generate AI Social Openers
 */
export const getSocialOpeners = async (userName: string, buddyName: string, sharedInterests: string[], lang: AppLanguage = 'EN'): Promise<string[]> => {
  const prompt = `Generate 3 creative and warm chat openers for ${userName} to send to ${buddyName}. 
  Shared interests: ${sharedInterests.join(', ')}. 
  Current context: Shanghai (sunny weather, a hot weekend coming up). 
  Keep them under 15 words. Format: Return ONLY a JSON array of 3 strings.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: { responseMimeType: "application/json" }
    });
    const result = JSON.parse(response.text || '[]');
    return Array.isArray(result) ? result : [];
  } catch {
    return ["Hi! Nice to meet you.", "Love your profile! How are you?", "Exploring Shanghai today?"];
  }
};

/**
 * FEATURE 2: Culture Vibe Interpreter
 */
export const interpretCulture = async (phrase: string, lang: AppLanguage = 'EN'): Promise<string> => {
  const prompt = `You are a "Cultural Vibe Interpreter" for Shanghai expats. 
  Explain the hidden non-verbal meaning of the Chinese social phrase: "${phrase}".
  Explain if it's a polite decline, a vague promise, or a real commitment. 
  Language: ${lang}. 
  Style: Insightful, concise, and helpful for social awkwardness.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview', // High reasoning task
      contents: prompt,
      config: { temperature: 0.7 }
    });
    return response.text || "I'm figuring out the vibe. Try another phrase!";
  } catch {
    return "Cultural nuance detected! This phrase is often used for politeness.";
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Message, AppLanguage, UserProfile } from '../types';
import { sendMessageToLink, getSocialOpeners } from '../services/geminiService';

interface ChatViewProps {
  lang: AppLanguage;
  userProfile: UserProfile | null;
  history: Message[];
  setHistory: React.Dispatch<React.SetStateAction<Message[]>>;
  onBack: () => void;
  initialPrompt: string | null;
  clearInitialPrompt: () => void;
}

const ChatView: React.FC<ChatViewProps> = ({ lang, userProfile, history, setHistory, onBack, initialPrompt, clearInitialPrompt }) => {
  const [input, setInput] = useState('');
  const [isTyping, setIsTyping] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const [isSearchOpen, setIsSearchOpen] = useState(false);
  const [showJumpButton, setShowJumpButton] = useState(false);
  const [isRegistered, setIsRegistered] = useState(false);
  const [viewMode, setViewMode] = useState<'private' | 'group'>('private');
  const [hubName, setHubName] = useState<string | null>(null);
  const [groupHistory, setGroupHistory] = useState<Message[]>([]);
  const [aiOpeners, setAiOpeners] = useState<string[]>([]);
  const scrollRef = useRef<HTMLDivElement>(null);

  const avatars = {
    guide: "https://lh3.googleusercontent.com/aida-public/AB6AXuD1AnjqkPoQm3pk-3kBpy77PCfjcc07Zlnpv4KgNiT4VZBC_YvZXFAgnfszjD5gYRcQ8AKG5tNiApQEfIJe4bjL5dP2uYBqK-NbYj07H-cC60gV85aAnOtQ6ebK6shs4tAtEPG0qJMPw-svNd8gylzgFUgBUtHPJsJsMN5oO8v8QoKdWgJwSj8_lK38sclH6lOz86DuHl2t9ANsHnIm_goxAjNsgLD3_WVL3aukvFRT2THSx2jSXX5UknXszs_L9D-0YQ0srpuDMiw",
  };

  const currentHistory = viewMode === 'group' ? groupHistory : history;

  useEffect(() => {
    if (scrollRef.current && !isSearchOpen) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
    }
  }, [history, groupHistory, isTyping, isSearchOpen, viewMode]);

  useEffect(() => {
    const handleScroll = () => {
      if (scrollRef.current) {
        const { scrollTop, scrollHeight, clientHeight } = scrollRef.current;
        const isNearBottom = scrollHeight - scrollTop - clientHeight < 150;
        if (currentHistory.length > 5) {
          setShowJumpButton(!isNearBottom);
        }
      }
    };
    const el = scrollRef.current;
    el?.addEventListener('scroll', handleScroll);
    return () => el?.removeEventListener('scroll', handleScroll);
  }, [currentHistory.length]);

  useEffect(() => {
    if (initialPrompt) {
      if (initialPrompt.startsWith('JOIN_GROUP:')) {
        const name = initialPrompt.replace('JOIN_GROUP:', '');
        handleJoinHubChat(name);
      } else if (initialPrompt.startsWith('SOCIAL_CHAT:')) {
        // FEATURE 1: Social Openers Trigger
        const buddyInfo = JSON.parse(initialPrompt.replace('SOCIAL_CHAT:', ''));
        const shared = buddyInfo.tags.filter((t: string) => 
          userProfile?.interests.some(ui => t.toLowerCase().includes(ui.toLowerCase()))
        );
        getSocialOpeners('You', buddyInfo.name, shared, lang).then(setAiOpeners);
        setViewMode('private');
      } else if (viewMode === 'private') {
        handleSend(initialPrompt);
      }
      clearInitialPrompt();
    }
  }, [initialPrompt]);

  const handleSend = async (messageText?: string) => {
    const textToSend = messageText || input;
    if (!textToSend.trim()) return;

    setAiOpeners([]); // Clear openers on any message send
    const userMessage: Message = { id: Date.now().toString(), sender: 'user', text: textToSend, timestamp: Date.now() };

    if (viewMode === 'group') {
      setGroupHistory(prev => [...prev, userMessage]);
    } else {
      setHistory(prev => [...prev, userMessage]);
    }

    setInput('');
    setIsTyping(true);
    const minDelay = new Promise(resolve => setTimeout(resolve, 800));

    try {
      if (viewMode === 'private') {
        const aiResponseText = await sendMessageToLink(textToSend, lang);
        await minDelay;
        const aiMessage: Message = { id: (Date.now() + 1).toString(), sender: 'ai', text: aiResponseText, timestamp: Date.now(), userQuery: textToSend };
        setHistory(prev => [...prev, aiMessage]);
      } else {
        await minDelay;
        const aiMessage: Message = { id: (Date.now() + 1).toString(), sender: 'ai', text: "That sounds great! Looking forward to seeing everyone there! ✨", timestamp: Date.now() };
        setGroupHistory(prev => [...prev, aiMessage]);
      }
    } catch (error) {
      console.error(error);
    } finally {
      setIsTyping(false);
    }
  };

  const handleJoinHubChat = (name: string) => {
    setViewMode('group');
    setHubName(name);
    const userName = "Alex"; 
    setGroupHistory([
      { id: 'h1', sender: 'ai', text: `Welcome to the ${name} Hub! 🏮`, timestamp: Date.now() - 2000 },
      { id: 'h2', sender: 'ai', text: `@${userName} Welcome to the community! This is your group space for ${name}. Feel free to share tips, ask questions, or just say hi to fellow members! ✨`, timestamp: Date.now() }
    ]);
  };

  const handleJoinGroup = () => {
    setViewMode('group');
    const userName = "Alex";
    const isArtInterested = userProfile?.interests?.some(i => i.toLowerCase().includes('art') || i.toLowerCase().includes('museum'));
    const interestEN = isArtInterested ? "art enthusiast" : "cycling enthusiast";

    setGroupHistory([
      { id: 'g1', sender: 'ai', text: `Welcome to the group chat! 🏮`, timestamp: Date.now() - 2000 },
      { id: 'g2', sender: 'ai', text: `@${userName} Welcome ${userName}! He is also a ${interestEN}. You guys can discuss routes for this Saturday! 🚲✨`, timestamp: Date.now() }
    ]);
  };

  const labels: Record<AppLanguage, string> = {
    EN: "Ask Link anything...", 
    CN: "问问 Link 任何事...", 
    JP: "Linkに質問...", 
    KR: "Link에게 질문...", 
    FR: "Demandez à Link...", 
    ES: "Pregunta a Link...",
    DE: "Frag Link etwas...",
    IT: "Chiedi a Link...",
    PT: "Perгunte ao Link...",
    RU: "Спроси Линка...",
    AR: "اسأل لينك أي شيء..."
  };

  const scrollToBottom = () => {
    if (scrollRef.current) {
      scrollRef.current.scrollTo({
        top: scrollRef.current.scrollHeight,
        behavior: 'smooth'
      });
      setShowJumpButton(false);
    }
  };

  const highlightText = (text: string, query: string) => {
    if (!query.trim()) return text;
    const parts = text.split(new RegExp(`(${query})`, 'gi'));
    return parts.map((part, i) => 
      part.toLowerCase() === query.toLowerCase() 
        ? <mark key={i} className="bg-yellow-200/80 dark:bg-yellow-500/40 text-slate-900 dark:text-white rounded px-1">{part}</mark> 
        : part
    );
  };

  const getHeaderTitle = () => {
    if (viewMode !== 'group') return 'we Link!';
    if (hubName) return hubName;
    return 'West Bund Art Walk Group';
  };

  return (
    <div className="flex flex-col h-full bg-gradient-to-b from-[#f0fff4] to-white dark:from-[#0a140f] dark:to-[#050a08] relative overflow-hidden transition-colors duration-500">
      <div className="absolute inset-0 pointer-events-none opacity-20">
        <div className="absolute top-[25%] right-[5%] text-4xl animate-float-slow">🥟</div>
        <div className="absolute top-[60%] left-[8%] text-3xl animate-float-fast" style={{ animationDelay: '1.5s' }}>🏮</div>
        <div className="absolute bottom-[20%] right-[15%] text-5xl animate-float-slow" style={{ animationDelay: '3s' }}>🗼</div>
      </div>

      <header className="sticky top-0 z-50 glass px-6 py-6 flex flex-col gap-4 border-b border-slate-100 dark:border-white/10 shadow-xl transition-all duration-300">
        <div className="flex items-center justify-between">
          <button 
            onClick={viewMode === 'group' ? () => { if (hubName) onBack(); else setViewMode('private'); } : onBack} 
            className="size-10 flex items-center justify-center rounded-2xl bg-slate-50 dark:bg-zinc-800 text-slate-600 dark:text-slate-300 active:scale-90 transition-all hover:bg-primary/20 hover:text-primary"
          >
            <span className="material-symbols-outlined font-black">arrow_back</span>
          </button>

          <div className="flex flex-col items-center">
            <div className="flex items-center gap-2">
              <div className="size-2 bg-primary rounded-full animate-pulse shadow-[0_0_8px_#13ec80]" />
              <h2 className="text-slate-900 dark:text-white font-black text-lg tracking-tighter italic">
                {getHeaderTitle()}
              </h2>
            </div>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => setIsSearchOpen(!isSearchOpen)}
              className={`size-10 rounded-2xl flex items-center justify-center transition-all ${isSearchOpen ? 'bg-primary text-[#0d1b14]' : 'bg-slate-50 dark:bg-zinc-800 text-slate-400'}`}
            >
              <span className="material-symbols-outlined font-black">{isSearchOpen ? 'close' : 'search'}</span>
            </button>
            <div className="size-10 rounded-full border-2 border-primary/30 p-1">
              <img 
                src={avatars.guide} 
                className="size-full object-cover rounded-full" 
                alt="Link" 
              />
            </div>
          </div>
        </div>

        {isSearchOpen && (
          <div className="animate-in slide-in-from-top duration-300">
            <div className="relative">
              <input 
                autoFocus
