                    <div className="px-4 py-1.5 bg-slate-50 dark:bg-white/5 rounded-full text-[10px] font-black uppercase text-gray-500 tracking-widest">{topic.hotRank}</div>
                  </div>
                </div>
              ))}
           </div>
        </div>
      )}
    </div>
  );
};

